#include <iostream>
#include <string>
#include <string_view>

class Person
{
private:
    std::string m_name;
    int m_age{};

public:
    Person(std::string_view name, int age)
        : m_name{ name }, m_age{ age }
    {
        std::cout << "Person constructed: " << m_name << ", age " << m_age << '\n';
    }

    ~Person()
    {
        std::cout << "Person destroyed\n";
    }

    std::string describe() const
    {
        return std::string{ m_name } + " (age " + std::to_string(m_age) + ")";
    }
};

class Employee : public Person
{
private:
    std::string m_department;

public:
    Employee(std::string_view name, int age, std::string_view department)
        : Person{ name, age }, m_department{ department }
    {
        std::cout << "Employee constructed: " << m_department << '\n';
    }

    ~Employee()
    {
        std::cout << "Employee destroyed\n";
    }

    std::string describe() const
    {
        return Person::describe() + ", " + std::string{ m_department } + " dept";
    }
};

class Manager : public Employee
{
private:
    int m_teamSize{};

public:
    Manager(std::string_view name, int age, std::string_view department, int teamSize)
        : Employee{ name, age, department }, m_teamSize{ teamSize }
    {
        std::cout << "Manager constructed: team of " << m_teamSize << '\n';
    }

    ~Manager()
    {
        std::cout << "Manager destroyed\n";
    }

    std::string describe() const
    {
        return Employee::describe() + ", manages " + std::to_string(m_teamSize);
    }
};

int main()
{
    std::string name{};
    int age{};
    std::string department{};
    std::cin >> name >> age >> department;

    int teamSize{};
    std::cin >> teamSize;

    {
        Manager mgr{ name, age, department, teamSize };
        std::cout << '\n';
        std::cout << mgr.describe() << '\n';
        std::cout << '\n';
    }

    return 0;
}

